import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.Culc7SYV.js";const p=JSON.parse('{"title":"Card Browser","description":"","frontmatter":{},"headers":[],"relativePath":"Card-Browser.md","filePath":"Card-Browser.md","lastUpdated":1773806339000}'),i={name:"Card-Browser.md"};function l(s,e,n,d,c,u){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="card-browser" tabindex="-1">Card Browser <a class="header-anchor" href="#card-browser" aria-label="Permalink to &quot;Card Browser&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Card Browser is a table view of all cards in your vault. Use it to find, filter, edit, and manage cards in bulk.</p><h2 id="main-controls" tabindex="-1">Main Controls <a class="header-anchor" href="#main-controls" aria-label="Permalink to &quot;Main Controls&quot;">​</a></h2><ul><li><strong>Sort</strong>: click a column header to sort; click again to reverse order.</li><li><strong>Search</strong>: text search across card fields.</li><li><strong>Filters</strong>: <ul><li>Type (Basic, Cloze, MCQ, IO, Ordered)</li><li>Stage (New, Learning, Review, Relearning, Suspended, Buried)</li><li>Due status (Due, Today, Later)</li></ul></li><li><strong>Reset</strong>: clears filters back to default.</li></ul><h2 id="edit-actions" tabindex="-1">Edit Actions <a class="header-anchor" href="#edit-actions" aria-label="Permalink to &quot;Edit Actions&quot;">​</a></h2><ul><li>Select one or more rows.</li><li>Use actions to edit, suspend/unsuspend, or clear selection.</li><li>Changes from edit actions appear in the table immediately.</li></ul><p>See <a href="./Suspending-Cards">Suspending Cards</a> for suspend behavior.</p><h2 id="table-controls" tabindex="-1">Table Controls <a class="header-anchor" href="#table-controls" aria-label="Permalink to &quot;Table Controls&quot;">​</a></h2><ul><li>Move through pages using controls at the bottom.</li><li>Change rows per page from the page-size selector.</li><li>Use <strong>Expand table / Collapse table</strong> to switch width.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li>If no rows appear, check active filters and search text first.</li><li>Some columns may be hidden if column visibility was changed.</li><li>Bulk actions only apply to selected rows.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Editing-Cards">Editing Cards</a></li><li><a href="./Suspending-Cards">Suspending Cards</a></li></ul>',15)])])}const g=a(i,[["render",l]]);export{p as __pageData,g as default};
